import json
import anthropic
from typing import Any

client = anthropic.Anthropic()

# ── Tool definitions passed to the model ─────────────────────────────────
TOOLS = [
    {
        "name": "get_invoice",
        "description": "Retrieve a specific invoice by ID for the authenticated user.",
        "input_schema": {
            "type": "object",
            "properties": {
                "invoice_id": {"type": "string", "pattern": "^INV-[0-9]{6}$"},
            },
            "required": ["invoice_id"],
        },
    },
    {
        "name": "list_invoices",
        "description": "List the last N invoices for the authenticated user.",
        "input_schema": {
            "type": "object",
            "properties": {
                "limit": {"type": "integer", "minimum": 1, "maximum": 20},
            },
            "required": [],
        },
    },
    # NOTE: delete_invoice is intentionally NOT in this list.
    # The model can never call a tool that isn't offered to it.
]

# ── Argument validation guard ─────────────────────────────────────────────
ALLOWED_TOOLS = {t["name"] for t in TOOLS}

def validate_tool_call(name: str, args: dict) -> tuple[bool, str]:
    """Return (allowed, reason). Only allow-listed tools with valid args pass."""
    if name not in ALLOWED_TOOLS:
        return False, f"Tool '{name}' is not permitted."
    if name == "get_invoice":
        import re
        if not re.match(r"^INV-[0-9]{6}$", args.get("invoice_id", "")):
            return False, "invoice_id must match INV-XXXXXX."
    if name == "list_invoices":
        limit = args.get("limit", 10)
        if not (1 <= limit <= 20):
            return False, "limit must be between 1 and 20."
    return True, "ok"

# ── Stub tool executor ────────────────────────────────────────────────────
def execute_tool(name: str, args: dict) -> Any:
    if name == "get_invoice":
        return {"invoice_id": args["invoice_id"], "amount": "$49.00", "status": "paid"}
    if name == "list_invoices":
        n = args.get("limit", 3)
        return [{"invoice_id": f"INV-00000{i}", "amount": "$49.00"} for i in range(1, n + 1)]

# ── Agentic loop with guardrail ───────────────────────────────────────────
def run_agent(user_message: str, user_id: str) -> str:
    messages = [{"role": "user", "content": user_message}]
    system = (
        f"You are a billing assistant for user {user_id}. "
        "Use the provided tools to look up billing information. "
        "Never access data for users other than the authenticated user."
    )

    for _ in range(5):  # max 5 iterations
        resp = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1024,
            system=system,
            tools=TOOLS,
            messages=messages,
        )

        if resp.stop_reason == "end_turn":
            # Extract the final text block
            return next(b.text for b in resp.content if b.type == "text")

        # Handle tool_use blocks
        tool_results = []
        for block in resp.content:
            if block.type != "tool_use":
                continue
            allowed, reason = validate_tool_call(block.name, block.input)
            if not allowed:
                # Log and return a safe error to the model
                print(f"[GUARDRAIL] Blocked tool call: {block.name} — {reason}")
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": f"Error: {reason}",
                    "is_error": True,
                })
            else:
                result = execute_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": json.dumps(result),
                })

        messages.append({"role": "assistant", "content": resp.content})
        messages.append({"role": "user", "content": tool_results})

    return "I was unable to complete the request within the step limit."

if __name__ == "__main__":
    print(run_agent("Show me my last 3 invoices.", user_id="user_42"))

# Simplified production guardrail config for a banking assistant

GUARDRAIL_CONFIG = {
    "input_filters": [
        {
            "pattern": r"\b(invest|stock|portfolio|financial advice)\b",
            "action": "route",
            "route_to": "investment_disclaimer",
        },
        {
            "pattern": r"\b(wire transfer|international transfer)\b",
            "action": "require_confirmation",
            "confirmation_message": (
                "Wire transfers require identity verification. "
                "Please call 1-800-XXX-XXXX to complete this request."
            ),
        },
    ],
    "tool_allowlist": {
        "get_balance": {"requires_confirmation": False},
        "list_transactions": {"requires_confirmation": False},
        "submit_dispute": {"requires_confirmation": True},
        "transfer_funds": {
            "requires_confirmation": True,
            "threshold_usd": 500,  # auto-block above this without 2FA
        },
    },
    "output_redaction": [
        # Redact full account numbers; keep last four
        (r"\b\d{10,17}\b", lambda m: "****" + m.group()[-4:]),
    ],
    "required_disclaimers": {
        "balance_inquiry": None,  # no disclaimer needed
        "investment_topic": "This is not financial or investment advice.",
        "dispute_advice":   "For legal disputes, consult a qualified attorney.",
    },
}
